        if (s.length() == 0) {
        return 0.0;
    }
    if (s.length() > 2 && s.charAt(0) == '0' && (s.charAt(1) == 'x' || s.charAt(1) == 'X')) {
                try {
            return Double.valueOf(Integer.parseInt(s.substring(2), 16));
