        query = query.substring("explain".length()).trim();
        statement.setExplain(true);
    }
    if (query.startsWith("measure")) {
        query = query.substring("measure".length()).trim();
        statement.setMeasure(true);
    }
    if (query.isEmpty()) {
                query = "//jcr:root";
    }
    statement.setOriginalQuery(query);
