    if (e == null) {
        old = null;
    } else {
        old = e.value;
        invalidate(key, hash);
    }
    e = new Entry<K, V>();
    e.key = key;
    e.value = value;
    e.memory = memory;
    int index = hash & mask;
    e.mapNext = entries[index];
    entries[index] = e;
    usedMemory += memory;
    if (usedMemory > maxMemory && mapSize > 0) {
                evict(e);
    }
    mapSize++;
        addToStack(e);
