                if (catchblock != null) {
                    add(catchblock);
                }
                if (childCount == 3) {
                    add("finally");
                    add(last, Context.PRESERVE_BLOCK);
                }
                break;
            }
        case Token.CATCH:
            Preconditions.checkState(childCount == 2);
            add("catch(");
            add(first);
            add(")");
            add(last, Context.PRESERVE_BLOCK);
            break;
        case Token.THROW:
            Preconditions.checkState(childCount == 1);
            add("throw");
            add(first);
                                    cc.endStatement(true);
            break;
        case Token.RETURN:
            add("return");
            if (childCount == 1) {
                add(first);
            } else {
                Preconditions.checkState(childCount == 0);
