        count++;
        depthTotal += depth;
    }
    if (count < maxCount) {
        depth++;
        int width = 0;
        boolean finished = true;
        for (ChildNodeEntry entry : state.getChildNodeEntries()) {
            if (count >= maxCount) {
                finished = false;
                break;
            }
            width++;
            visit(entry.getNodeState());
        }
        if (finished && width > 0) {
            widthTotal += width;
            widthCount++;
        }
        depth--;
    }
