                        listener.error('\'' + jcrPath + "' is not a valid path. " + "Index number invalid: " + index);
                        return false;
                    }
                    state = STATE_INDEX_END;
                } else {
                    listener.error('\'' + jcrPath + "' is not a valid path. '" + c + "' not a valid name character.");
                    return false;
                }
