        stepStart = nextStep;
        if (manager.reset(stepStart, y) && !lastStep) {
                                    computeDerivatives(stepStart, y, yDotK[0]);
        }
                stepSize = forward ? step : -step;
    }
    final double stopTime = stepStart;
    stepStart = Double.NaN;
    stepSize = Double.NaN;
