        case Token.NUMBER:
        case Token.TRUE:
        case Token.FALSE:
            return true;
                case Token.BITAND:
        case Token.BITNOT:
        case Token.BITOR:
        case Token.BITXOR:
                case Token.NOT:
        case Token.NEG:
            return isValidDefineValue(val.getFirstChild(), defines);
                case Token.NAME:
        case Token.GETPROP:
            if (val.isQualifiedName()) {
                return defines.contains(val.getQualifiedName());
            }
    }
    return false;
