protected void computeInterpolatedStateAndDerivatives(final double theta, final double oneMinusThetaH) {
    if (!vectorsInitialized) {
        if (v == null) {
            v = new double[7][];
            for (int k = 0; k < 7; ++k) {
                v[k] = new double[interpolatedState.length];
