    }
    LOGGER.trace("AbstractConfiguration stopped {} Appenders.", appenderCount);
    int loggerCount = 0;
    for (final LoggerConfig logger : loggers.values()) {
                logger.clearAppenders();
                if (alreadyStopped.contains(logger)) {
            continue;
