    String since = c.getChild("since").getValue();
    if (since != null) {
        mojo.setSince(since);
    }
    PlexusConfiguration deprecated = c.getChild("deprecated", false);
    if (deprecated != null) {
        mojo.setDeprecated(deprecated.getValue());
    }
    String phase = c.getChild("phase").getValue();
    if (phase != null) {
        mojo.setPhase(phase);
