        if (index == 1 && isVowel(charAt(value, 0)) && !slavoGermanic) {
            result.append("KN", "N");
        } else if (!contains(value, index + 2, 2, "EY") && charAt(value, index + 1) != 'Y' && !slavoGermanic) {
            result.append("N", "KN");
        } else {
            result.append("KN");
        }
        index = index + 2;
    } else if (contains(value, index + 1, 2, "LI") && !slavoGermanic) {
        result.append("KL", "L");
        index += 2;
