            stmt.setBytes(1, rawId);
            stmt.setBytes(2, bytes);
            stmt.setTimestamp(3, ts);
            stmt.setBytes(4, rawId);
            stmt.executeUpdate();
        } finally {
            stmt.close();
        }
    } finally {
        con.close();
    }
    return new Id(rawId);
