                        v.getNameNode().addChildToFront(NodeUtil.newQualifiedNameNode(compiler.getCodingConvention(), globalName, n, name));
            recordAlias(v);
        } else {
                        report(t, n, GOOG_SCOPE_NON_ALIAS_LOCAL, n.getString());
        }
    }
