                        if (result.getPattern().isOutCapable()) {
                                result.getOut().copyFrom(source.getIn());
            } else {
                                result.getIn().copyFrom(source.getIn());
            }
        }
        if (source.hasProperties()) {
            result.getProperties().putAll(source.getProperties());
        }
    }
