@Override
public void enterScope(NodeTraversal t) {
    if (t.inGlobalScope()) {
                return;
    }
    if (LiveVariablesAnalysis.MAX_VARIABLES_TO_ANALYZE < t.getScope().getVarCount()) {
        return;
