private void escape(StringBuilder builder, CharSequence str) {
    final int len = str.length();
    for (int i = 0; i < len; i++) {
        char c = str.charAt(i);
        if (c == '%') {
            builder.append("%25");
        } else if (c == ';') {
            builder.append("%3b");
        } else {
            builder.append(c);
        }
    }
