private String makeRelative(String path, int expectedLen) {
    String relPath = path;
    if (relPath.startsWith("../"))
        relPath = relPath.substring(3);
    while (relPath.endsWith("/")) relPath = relPath.substring(0, relPath.length() - 1);
    while (relPath.startsWith("/")) relPath = relPath.substring(1);
    String[] tokens = relPath.split("/");
        boolean containsEmpty = false;
    for (String token : tokens) {
        if (token.equals("")) {
            containsEmpty = true;
            break;
        }
    }
    if (containsEmpty) {
        ArrayList<String> tmp = new ArrayList<String>();
        for (String token : tokens) {
            if (!token.equals("")) {
                tmp.add(token);
            }
        }
        tokens = tmp.toArray(new String[tmp.size()]);
    }
    if (tokens.length > 3) {
