        putShort(nameLen, buf, LFH_FILENAME_LENGTH_OFFSET);
        putShort(extra.length, buf, LFH_EXTRA_LENGTH_OFFSET);
        System.arraycopy(name.array(), name.arrayOffset(), buf, LFH_FILENAME_OFFSET, nameLen);
