private Node parseFunctionType(JsDocToken token) {
        if (token != JsDocToken.LP) {
        return reportTypeSyntaxWarning("msg.jsdoc.missing.lp");
    }
    Node functionType = newNode(Token.FUNCTION);
    Node parameters = null;
    skipEOLs();
    if (!match(JsDocToken.RP)) {
        token = next();
        boolean hasParams = true;
        if (token == JsDocToken.STRING) {
            String tokenStr = stream.getString();
            boolean isThis = "this".equals(tokenStr);
            boolean isNew = "new".equals(tokenStr);
            if (isThis || isNew) {
                if (match(JsDocToken.COLON)) {
                    next();
                    skipEOLs();
                    Node contextType = wrapNode(isThis ? Token.THIS : Token.NEW, parseTypeName(next()));
                    if (contextType == null) {
                        return null;
                    }
                    functionType.addChildToFront(contextType);
                } else {
                    return reportTypeSyntaxWarning("msg.jsdoc.missing.colon");
                }
                if (match(JsDocToken.COMMA)) {
                    next();
                    skipEOLs();
                    token = next();
                } else {
                    hasParams = false;
                }
            }
        }
        if (hasParams) {
            parameters = parseParametersType(token);
            if (parameters == null) {
                return null;
            }
        }
    }
    if (parameters != null) {
        functionType.addChildToBack(parameters);
    }
    skipEOLs();
    if (!match(JsDocToken.RP)) {
        return reportTypeSyntaxWarning("msg.jsdoc.missing.rp");
    }
    skipEOLs();
    Node resultType = parseResultType(next());
    if (resultType == null) {
        return null;
    } else {
        functionType.addChildToBack(resultType);
    }
    return functionType;
},2

private static boolean isAlreadyRunning(NodeStore store, String name) {
    NodeState indexState = store.getRoot().getChildNode(INDEX_DEFINITIONS_NAME);
        if (!indexState.exists()) {
        return false;
    }
        if (STATUS_RUNNING.equals(indexState.getString(name + "-status"))) {
        PropertyState startTime = indexState.getProperty(name + "-start");
        Calendar start = Conversions.convert(startTime.getValue(Type.DATE)).toCalendar();
        Calendar now = Calendar.getInstance();
        long delta = now.getTimeInMillis() - start.getTimeInMillis();
                if (TimeUnit.MILLISECONDS.toMinutes(delta) > ASYNC_TIMEOUT) {
            log.info("Async job found which stated on {} has timed out in {} minutes. " + "This node would take over the job.", startTime.getValue(Type.DATE), ASYNC_TIMEOUT);
            return false;
        }
        return true;
    }
    return false;
