        } catch (IOException e) {
            if (url.toString().indexOf(".jar!") >= 0) {
                if (log.isDebugEnabled()) {
                    log.debug("getLastModified for " + url + " failed: " + e.getMessage());
                }
            } else {
                log.warn("getLastModified for " + url + " failed: " + e.getMessage());
            }
                        return null;
        }
    }
    return Time.milliseconds(lastModified);
